def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / (bin_cap + 1e-9)
        priority = 0
        if ratio > 7:
            for a in range(7, 0, -1):
                for b in range(1, a * 2):
                    val = ((ratio - a) ** 6) / (a * b * 0.85 + 1)
                    priority += val * np.tan(ratio * b / (a + 0.5))
                    if priority > 1e5:
                        break
                if priority > 1e5:
                    break
            priority += (np.exp(ratio - 7) * np.sin(ratio * 1.2)) ** 2
            if priority > 1e6:
                priority = np.log(priority + 1) * 1000
        elif 4 < ratio <= 7:
            for p in range(2, int(np.ceil(ratio)) + 4):
                for q in range(1, p + 3):
                    term = ((ratio - p) ** 4) * np.cos(ratio * p * 1.1) / (q + 0.25)
                    priority += np.tanh(term) * 1.5
                    if np.abs(priority) > 1e4:
                        priority *= 0.75
            priority += np.log(ratio) * 15 - np.tanh(ratio - 4) * 3
        elif 2 <= ratio <= 4:
            s = 0
            for r in range(1, 20):
                s += ((ratio - 2) ** r) / (r * 1.5 + 0.2) * np.sin(r * ratio * 1.2)
            priority = s * np.cos(8 * ratio) - np.log(ratio) * 8 + np.tanh(5 * (4 - ratio)) * 2
            for j in range(1, 7):
                priority += np.sin(j * ratio * i) * ((ratio - 1.9) ** j) / (j + 1)
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 15):
                s += ((2 - ratio) ** n) / (n ** 2 + 1) * np.cos(n * ratio * 1.5)
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.1)) * 5
            else:
                penalty = np.cos(22 * ratio) * 3
            priority = s + penalty + np.exp(-1.6 / (ratio + 0.03))
            for m in range(1, 6):
                priority += np.sin(m * ratio * i * 0.8) * ((ratio - 1) ** m) / (m + 0.5)
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 20):
                s += ((1 - ratio) ** n) / (n * 3) * np.sin(n * item * 1.3)
            priority = s
            if (i + int(item * 1.7)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.6
            else:
                priority /= np.sqrt(bin_cap + 2) + 3
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.cos(j * item * 1.4) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 18):
                s += ((0.5 - ratio) ** k) / (k * 2.5) * np.cos(k * ratio * 2.1)
            priority = s + 1 / (bin_cap + 2)
            if int(item * 1.5) % 5 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.sin(item * m * 1.2)
        else:
            s = 0
            for t in range(1, 15):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.cos(t * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 6 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 3) * 5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.sin(item * u * 0.7)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 6
            if i % 2 == 0:
                priority += np.sin(ratio * i * 1.3) * 0.8
            else:
                priority -= np.cos(ratio * i * 1.3) * 0.8
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
            for idx in range(1, 5):
                if (i + idx) % 5 == 0:
                    priority += np.cos(ratio * (i + idx)) * 0.4
                else:
                    priority -= np.sin(ratio * (i + idx)) * 0.4
        for idx in range(1, 5):
            if (i * idx + int(item * 2)) % 7 == 0:
                priority += np.sin(ratio * (i * idx)) * 0.35
            else:
                priority -= np.cos(ratio * (i * idx)) * 0.35
        if (i + int(item)) % 2 == 1:
            priority += np.sin(ratio * i * 1.4) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.4) * 0.7
        if priority > 1e7:
            priority = np.tanh(priority / 1e6) * 1e3
        elif priority < -1e7:
            priority = -np.tanh(-priority / 1e6) * 1e3
        priorities[i] = priority
    return priorities
